function basicCalculator()
    % Display a welcome message
    disp('Welcome to the Basic Calculator!');

    % Loop indefinitely until the user decides to exit
    while true
        % Prompt the user for the first number
        num1 = input('Enter the first number: ');

        % Prompt the user for the second number
        num2 = input('Enter the second number: ');

        % Prompt the user for the operation
        operation = input('Choose an operation (+, -, *, /): ', 's');

        % Perform the selected operation and display the result
        switch operation
            case '+'
                result = num1 + num2;
                disp(['Result: ', num2str(result)]);
            case '-'
                result = num1 - num2;
                disp(['Result: ', num2str(result)]);
            case '*'
                result = num1 * num2;
                disp(['Result: ', num2str(result)]);
            case '/'
                if num2 ~= 0
                    result = num1 / num2;
                    disp(['Result: ', num2str(result)]);
                else
                    disp('Error: Division by zero is not allowed.');
                end
            otherwise
                disp('Invalid operation. Please choose one of the following: +, -, *, /');
        end

        % Ask the user if they want to perform another calculation
        continueCalculation = input('Do you want to perform another calculation? (yes/no): ', 's');
        if strcmpi(continueCalculation, 'no')
            break
        end
    end

    % Display a farewell message
    disp('Thank you for using the Basic Calculator! Goodbye.');
end

% Call the function to start the calculator
basicCalculator();
```

### Explanation:
- **Input Handling**: The script uses `input` to get numbers and operations from the user.
- **Switch Statement**: A `switch` statement is used to determine which operation to perform based on the user's input.
- **Error Handling**: Division by zero is handled to avoid runtime errors.
- **Loop**: The script runs in a loop, allowing the user to perform multiple calculations until they choose to exit.

To use this script, simply copy and paste it into a `.m` file in MATLAB

